diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index cdb2c11ef046..d025a9e17e76 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2673,8 +2673,20 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
     // Propagate sign argument through nested calls:
     // copysign Mag, (copysign ?, X) --> copysign Mag, X
     Value *X;
-    if (match(Sign, m_Intrinsic<Intrinsic::copysign>(m_Value(), m_Value(X))))
-      return replaceOperand(*II, 1, X);
+    if (match(Sign, m_Intrinsic<Intrinsic::copysign>(m_Value(), m_Value(X)))) {
+      FastMathFlags OuterFMF = II->getFastMathFlags();
+      auto *InnerCI = cast<IntrinsicInst>(Sign);
+      FastMathFlags InnerFMF = InnerCI->getFastMathFlags();
+      // Intersect flags: keep only flags present in both.
+      OuterFMF.setNoNaNs(OuterFMF.noNaNs() && InnerFMF.noNaNs());
+      OuterFMF.setNoInfs(OuterFMF.noInfs() && InnerFMF.noInfs());
+      OuterFMF.setNoSignedZeros(OuterFMF.noSignedZeros() && InnerFMF.noSignedZeros());
+      Value *NewCSVal = Builder.CreateBinaryIntrinsic(Intrinsic::copysign, Mag, X,
+                                                      nullptr, II->getName());
+      CallInst *NewCS = cast<CallInst>(NewCSVal);
+      NewCS->setFastMathFlags(OuterFMF);
+      return replaceInstUsesWith(*II, NewCS);
+    }

     // Clear sign-bit of constant magnitude:
     // copysign -MagC, X --> copysign MagC, X

