+        FMF.setNoInfs(false);
+      // nsz flag can be preserved as it only affects sign of zero.
+      if (FMF != II->getFastMathFlags())
+        II->setFastMathFlags(FMF);
       return replaceOperand(*II, 1, X);
+    }

